    @PostMapping(value = "/api/v4/files", consumes = "application/octet-stream")
    MattermostFileUploadResp uploadFileWithQueryParam(
            @RequestHeader("Authorization") String authorization,
            @RequestParam("channel_id") String channelId,
            @RequestParam("filename") String filename,
            @RequestBody byte[] file
    );

    @GetMapping(value = "/api/v4/users/email/{email}", produces = "application/json")
    MattermostUserInfoResp getUserByEmail(
            @RequestHeader("Authorization") String authorization,
            @PathVariable("email") String email
    );

    @PostMapping(value = "/api/v4/channels/direct", consumes = "application/json")
    MattermostDirectChannelResp createDirectMessageChannel(
            @RequestHeader("Authorization") String authorization,
            @RequestBody List<String> userIds
    );

    /**
     * 下载MM文件
     */
    @GetMapping(value = "/api/v4/files/{fileId}")
    byte[] downloadFile(
            @RequestHeader("Authorization") String authorization,
            @PathVariable("fileId") String fileId
    );
}

