package com.yottastudios.ns.collabspace.third.service;

import cn.hutool.json.JSONUtil;
import com.yottastudios.ns.collabspace.third.feign.OAChnService;
import com.yottastudios.ns.collabspace.third.req.OAChnSendRequest;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.util.Collection;
import java.util.HashMap;
import java.util.Map;

/**
 * Knock 消息服务，通过 OA Channel 发送机器人消息
 */
@Slf4j
@Service
public class KnockService {

    /** 机器人消息签名key */
    private static final String SIGN_KEY_ROBOT = "knock_send_robot_msg";

    /** 机器人名称：Yottatable */
    private static final String ROBOT_NAME = "yotta-Yottatable";

    @Resource
    private OAChnService oaChnService;

    @Value("${oa.chn.host}")
    private String oaChnHost;

    @Value("${oa.chn.client-id}")
    private String clientId;

    @Value("${oa.chn.client-secret}")
    private String clientSecret;

    /**
     * 通过 Yottatable 机器人发送富文本消息给指定用户
     *
     * @param nicknames 接收人昵称列表
     * @param title     消息标题
     * @param content   消息内容
     */
    public void sendRobotRichMsg(Collection<String> nicknames, String title, String content) {
        Map<String, Object> body = new HashMap<>();
        body.put("nicknames", nicknames);
        body.put("robot_name", ROBOT_NAME);
        // 富文本消息体
        Map<String, String> richContent = new HashMap<>();
        richContent.put("title", title);
        richContent.put("content", content);
        body.put("content", JSONUtil.toJsonStr(richContent));
        body.put("msg_type", "MSG_TYPE_RICH_CARD");

        String payload = JSONUtil.toJsonStr(body);
        String sign = oaChnService.getSign(clientId, SIGN_KEY_ROBOT, payload, clientSecret);

        OAChnSendRequest request = OAChnSendRequest.builder()
                .clientId(clientId)
                .key(SIGN_KEY_ROBOT)
                .payload(payload)
                .sign(sign)
                .build();

        String url = oaChnHost + "/third-api/request";
        log.info("[lbl][2087-消息推送][Knock][SEND] 发送富文本消息, url={}, robotName={}, nicknameCount={}, nicknames={}, title={}, contentLength={}",
                url, ROBOT_NAME, nicknames.size(), nicknames, title, content.length());
        log.info("[lbl][2087-消息推送][Knock][SEND] 请求详情: clientId={}, key={}, payloadLength={}, sign={}", clientId, SIGN_KEY_ROBOT, payload.length(), sign);
        Object result = oaChnService.send(request);
        log.info("[lbl][2087-消息推送][Knock][SEND] 响应: {}", JSONUtil.toJsonStr(result));
    }
}

