public class AnnouncementFormatConverter {

    private AnnouncementFormatConverter() {
    }

    /**
     * HTML → Knock 富文本格式
     * Knock 使用自定义XML标签：
     * <font bold="true">加粗</font>
     * <font color="red">红色</font>
     * <link url="https://example.com">链接文字</link>
     */
    public static String toKnockMarkdown(String html) {
        if (StrUtil.isBlank(html)) {
            return "";
        }
        return convertToKnockFormat(html);
    }

    /**
     * HTML → MM markdown 格式
     */
    public static String toMmMarkdown(String html) {
        if (StrUtil.isBlank(html)) {
            return "";
        }
        return convertToMarkdown(html);
    }

    private static final Pattern RGB_PATTERN = Pattern.compile("rgb\\(\\s*(\\d+)\\s*,\\s*(\\d+)\\s*,\\s*(\\d+)\\s*\\)");

    /** Knock支持的命名颜色及其RGB值 */
    private static final int[][] NAMED_COLORS = {
            {255, 0, 0},       // red
            {0, 128, 0},       // green
            {0, 0, 255},       // blue
            {255, 255, 0},     // yellow
            {255, 165, 0},     // orange
            {128, 0, 128},     // purple
            {0, 0, 0},         // black
            {128, 128, 128},   // gray
    };
    private static final String[] NAMED_COLOR_NAMES = {
            "red", "green", "blue", "yellow", "orange", "purple", "black", "gray"
    };

    /**
     * 将CSS颜色值转为Knock支持的命名颜色，rgb()取最近色
     */
    private static String normalizeColor(String cssColor) {
        Matcher m = RGB_PATTERN.matcher(cssColor);
        if (m.matches()) {
            int r = Integer.parseInt(m.group(1));
            int g = Integer.parseInt(m.group(2));
            int b = Integer.parseInt(m.group(3));
            return closestNamedColor(r, g, b);
        }
        return cssColor;
    }

    private static String closestNamedColor(int r, int g, int b) {
        int minDist = Integer.MAX_VALUE;
        String closest = "red";
        for (int i = 0; i < NAMED_COLORS.length; i++) {
            int dr = r - NAMED_COLORS[i][0];
            int dg = g - NAMED_COLORS[i][1];
            int db = b - NAMED_COLORS[i][2];
            int dist = dr * dr + dg * dg + db * db;
            if (dist < minDist) {
                minDist = dist;
                closest = NAMED_COLOR_NAMES[i];
            }
        }
        return closest;
    }

    private static String convertToKnockFormat(String html) {
        String result = html;

        // 处理加粗 <b>/<strong> → <font bold="true">
        result = result.replaceAll("<(b|strong)>(.*?)</\\1>", "<font bold=\"true\">$2</font>");
