        return cssColor;
    }

    private static String closestNamedColor(int r, int g, int b) {
        int minDist = Integer.MAX_VALUE;
        String closest = "red";
        for (int i = 0; i < NAMED_COLORS.length; i++) {
            int dr = r - NAMED_COLORS[i][0];
            int dg = g - NAMED_COLORS[i][1];
            int db = b - NAMED_COLORS[i][2];
            int dist = dr * dr + dg * dg + db * db;
            if (dist < minDist) {
                minDist = dist;
                closest = NAMED_COLOR_NAMES[i];
            }
        }
        return closest;
    }

    private static String convertToKnockFormat(String html) {
        String result = html;

        // 处理加粗 <b>/<strong> → <font bold="true">
        result = result.replaceAll("<(b|strong)>(.*?)</\\1>", "<font bold=\"true\">$2</font>");
        result = result.replaceAll("<(b|strong)\\s[^>]*>(.*?)</\\1>", "<font bold=\"true\">$2</font>");

        // 处理斜体 <i>/<em> → 直接去标签（Knock不支持斜体）
        result = result.replaceAll("<(i|em)>(.*?)</\\1>", "$2");
        result = result.replaceAll("<(i|em)\\s[^>]*>(.*?)</\\1>", "$2");

        // 处理字色 <span style="color:xxx"> → <font color="xxx">，rgb()转hex
        Pattern colorPattern = Pattern.compile("<span\\s+style=\"[^\"]*color:\\s*([^;\"]+)[^\"]*\">(.*?)</span>", Pattern.DOTALL);
        Matcher colorMatcher = colorPattern.matcher(result);
        StringBuilder colorSb = new StringBuilder();
        while (colorMatcher.find()) {
            String colorVal = normalizeColor(colorMatcher.group(1).trim());
            colorMatcher.appendReplacement(colorSb, "<font color=\"" + colorVal + "\">" + Matcher.quoteReplacement(colorMatcher.group(2)) + "</font>");
        }
        colorMatcher.appendTail(colorSb);
        result = colorSb.toString();

        // 处理链接 <a href="..."> → <link url="...">
        result = result.replaceAll("<a\\s+href=\"([^\"]+)\"[^>]*>(.*?)</a>", "<link url=\"$1\">$2</link>");

        // 处理无序列表
        result = result.replaceAll("<ul[^>]*>", "");
        result = result.replaceAll("</ul>", "");
        result = result.replaceAll("<li[^>]*>(.*?)</li>", "- $1\n");

        // 处理有序列表
        result = result.replaceAll("<ol[^>]*>", "");
        result = result.replaceAll("</ol>", "");

        // 处理标题 → 加粗
        for (int i = 1; i <= 6; i++) {
            result = result.replaceAll("<h" + i + "[^>]*>(.*?)</h" + i + ">", "<font bold=\"true\">$1</font>\n");
        }

        // 处理换行和段落
        result = result.replaceAll("<br\\s*/?>", "\n");
        result = result.replaceAll("<p[^>]*>(.*?)</p>", "$1\n");
        result = result.replaceAll("<div[^>]*>(.*?)</div>", "$1\n");

        // 清除剩余HTML标签（但保留 <font> <link> 这些Knock标签）
        result = result.replaceAll("<(?!/?font\\b)(?!/?link\\b)[^>]+>", "");

        // 处理HTML实体
        result = result.replace("&nbsp;", " ");
        result = result.replace("&amp;", "&");
        result = result.replace("&lt;", "<");
        result = result.replace("&gt;", ">");
        result = result.replace("&quot;", "\"");

        // 合并多余空行
        result = result.replaceAll("\n{3,}", "\n\n");

        return result.trim();
    }

    private static String convertToMarkdown(String html) {
        String result = html;

        // 处理加粗 <b>/<strong>
        result = result.replaceAll("<(b|strong)>(.*?)</\\1>", "**$2**");
        result = result.replaceAll("<(b|strong)\\s[^>]*>(.*?)</\\1>", "**$2**");

        // 处理斜体 <i>/<em>
        result = result.replaceAll("<(i|em)>(.*?)</\\1>", "*$2*");
        result = result.replaceAll("<(i|em)\\s[^>]*>(.*?)</\\1>", "*$2*");

        // 处理字色 <span style="color:..."> → 转为加粗
        Pattern colorPattern = Pattern.compile("<span\\s+style=\"[^\"]*color[^\"]*\">(.*?)</span>", Pattern.DOTALL);
        Matcher colorMatcher = colorPattern.matcher(result);
        result = colorMatcher.replaceAll("**$1**");

        // 处理链接 <a href="...">
        result = result.replaceAll("<a\\s+href=\"([^\"]+)\"[^>]*>(.*?)</a>", "[$2]($1)");

        // 处理无序列表
        result = result.replaceAll("<ul[^>]*>", "");
        result = result.replaceAll("</ul>", "");
        result = result.replaceAll("<li[^>]*>(.*?)</li>", "- $1\n");

        // 处理有序列表
        result = result.replaceAll("<ol[^>]*>", "");
        result = result.replaceAll("</ol>", "");

        // 处理标题 <h1>-<h6>
        for (int i = 1; i <= 6; i++) {
            String hashes = "#".repeat(i);
            result = result.replaceAll("<h" + i + "[^>]*>(.*?)</h" + i + ">", hashes + " $1\n");
        }

        // 处理换行和段落
        result = result.replaceAll("<br\\s*/?>", "\n");
        result = result.replaceAll("<p[^>]*>(.*?)</p>", "$1\n");
        result = result.replaceAll("<div[^>]*>(.*?)</div>", "$1\n");

        // 清除剩余HTML标签
        result = result.replaceAll("<[^>]+>", "");

        // 处理HTML实体
        result = result.replace("&nbsp;", " ");
        result = result.replace("&amp;", "&");
        result = result.replace("&lt;", "<");
        result = result.replace("&gt;", ">");
        result = result.replace("&quot;", "\"");

        // 合并多余空行
        result = result.replaceAll("\n{3,}", "\n\n");

        return result.trim();
    }
